// Unit 5. Mi Día
// Daily Routine & Reflexive Verbs

export default {n:5,lang:"es",srcLang:"en",track:"v2",title:"Mi Día",sub:"Daily Routine & Reflexive Verbs",icon:"🌅",level:"A1.2",color:"#7B5EE8",lessons:[
  {id:"esp5l1",title:"Por la Mañana",icon:"🌤️",xp:15,board:true,steps:[
        {type:"intro",title:"Por la Mañana",desc:"Learn morning routine vocabulary and reflexive verbs.",goals:["Name 6 morning activities","Understand reflexive verbs","Use me/te/se pronouns"]},
        {type:"teach",trg:"despertarse",src:"to wake up",pos:"verb",gender:null,phonetic:"des-per-TAR-seh",note:"Reflexive + stem-changing (e to ie): me despierto, te despiertas, se despierta.",example:"A: ¿A qué hora te despiertas?\nB: Me despierto a las siete.",exampleSrc:"A: What time do you wake up?\nB: I wake up at seven.",funFact:"Reflexive from 'despertar' (to wake someone). Without the reflexive 'se,' it means to wake someone up. With 'se,' you wake yourself up. Reflexive marks self-action."},
        {type:"teach",trg:"levantarse",src:"to get up",pos:"verb",gender:null,phonetic:"leh-ban-TAR-seh",note:"Reflexive -ar verb: me levanto, te levantas, se levanta, nos levantamos.",example:"A: ¿Te levantas temprano?\nB: Sí, me levanto a las seis y media.",exampleSrc:"A: Do you get up early?\nB: Yes, I get up at six thirty.",funFact:"Reflexive from 'levantar' (to lift, raise). 'Levantarse' = to lift oneself up, i.e. get up from bed. The reflexive transforms transitive verbs into self-directed ones."},
        {type:"teach",trg:"ducharse",src:"to shower",pos:"verb",gender:null,phonetic:"doo-CHAR-seh",note:"Reflexive -ar verb: me ducho, te duchas, se ducha.",example:"A: ¿Te duchas por la mañana o por la noche?\nB: Me ducho por la mañana.",exampleSrc:"A: Do you shower in the morning or at night?\nB: I shower in the morning.",funFact:"Reflexive from 'ducha' (shower). Parallel to English 'to shower (oneself).' Spanish makes the reflexive explicit; English has absorbed it implicitly."},
        {type:"teach",trg:"vestirse",src:"to get dressed",pos:"verb",gender:null,phonetic:"bes-TEER-seh",note:"Reflexive + stem-changing (e to i): me visto, te vistes, se viste.",example:"A: ¿Ya te has vestido?\nB: No, todavía estoy en pijama.",exampleSrc:"A: Have you gotten dressed yet?\nB: No, I'm still in my pajamas.",funFact:"Reflexive + e→i stem change. 'Me visto' (I dress myself). Without the reflexive: 'vestir a alguien' (to dress someone else). Spanish distinguishes; English blurs."},
        {type:"teach",trg:"desayunar",src:"to have breakfast",pos:"verb",gender:null,phonetic:"deh-sah-yoo-NAR",note:"Regular -ar verb (NOT reflexive): desayuno, desayunas, desayuna.",example:"A: ¿Qué desayunas?\nB: Desayuno café con tostadas.",exampleSrc:"A: What do you have for breakfast?\nB: I have coffee with toast.",funFact:"From 'des-' (un-) + 'ayunar' (to fast). Literally 'to unfast,' mirroring English 'breakfast' = break + fast. The shared metaphor is ancient: Romans already described the morning meal this way."},
        {type:"tip",title:"Reflexive Verbs",text:"Reflexive verbs show the action on YOURSELF:\nMe despierto = I wake (myself) up\nTe duchas = You shower (yourself)\nSe viste = He/she dresses (himself/herself)\n\nPronouns: me, te, se, nos, se\nThe pronoun goes BEFORE the conjugated verb.\n\nNot reflexive: desayunar (you don't breakfast yourself!).",icon:"💡"},
        {type:"mc",q:"Which is the correct 'yo' form of despertarse?",opts:["Me despierto","Me desperto","Yo despierto","Me despierta"],ans:"Me despierto",hint:"Reflexive pronoun me + stem change e to ie in the root."},
        {type:"fb",opts:["se","me","te","nos"],hint:"Third person reflexive pronoun for 'she showers herself'.",s:"Ella {1} ducha por la mañana.",a:"se"},
        {type:"match",pairs:[{trg:"me despierto",src:"I wake up"},{trg:"te levantas",src:"you get up"},{trg:"se ducha",src:"he/she showers"},{trg:"me visto",src:"I get dressed"},{trg:"desayuno",src:"I have breakfast"}]},
        {type:"mc",q:"Which verb is NOT reflexive?",opts:["ducharse","desayunar","vestirse","levantarse"],ans:"desayunar",hint:"You don't do breakfast TO yourself. It has no reflexive pronoun."},
        {type:"fb",opts:["levantas","levanto","levanta","levantamos"],hint:"Asking 'you' (tú) what time you get up.",s:"¿A qué hora te {1}?",a:"levantas"},
        {type:"mc",q:"Translate: 'I get dressed at eight.'",opts:["Visto me a las ocho","Me vesto a las ocho","Me visto a las ocho","Me viste a las ocho"],ans:"Me visto a las ocho",hint:"Reflexive pronoun before the verb. Stem changes e to i."},
        {type:"drag_fill",hint:"First I wake up, then I shower, then I eat breakfast.",s:"Primero {1} {2}, luego {3} {4} y después desayuno.",blanks:{"1":"me","2":"despierto","3":"me","4":"ducho"},pool:["me","despierto","me","ducho","se","levanto"]},
        {type:"fb",opts:["nos","me","se","te"],hint:"The reflexive pronoun for 'we' (nosotros).",s:"Nosotros {1} levantamos a las siete.",a:"nos"},
        {type:"mc",q:"'Se viste rápido' means:",opts:["We get dressed quickly","I get dressed quickly","You get dressed quickly","He/she gets dressed quickly"],ans:"He/she gets dressed quickly",hint:"'Se' is the third person reflexive pronoun."},
        {type:"fb",opts:["despierto","levanto","ducho","visto"],hint:"The first thing you do when the alarm rings.",s:"Me {1} a las siete todos los días.",a:"despierto"},
        {type:"mc",q:"Which reflexive pronoun matches the first person plural subject?",opts:["nos","me","se","te"],ans:"nos",hint:"The plural form of 'we' acting on ourselves."}
  ]},
  {id:"esp5l2",title:"Verbos -ar",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"Verbos -ar",desc:"Master the present tense of regular -ar verbs.",goals:["Conjugate 6 regular -ar verbs","Use all person forms","Build sentences with -ar verbs"]},
        {type:"teach",trg:"hablar",src:"to speak / to talk",pos:"verb",gender:null,phonetic:"ah-BLAR",note:"-ar verb: hablo, hablas, habla, hablamos, hablan. The H is silent!",example:"A: ¿Hablas español?\nB: Sí, hablo un poco de español.",exampleSrc:"A: Do you speak Spanish?\nB: Yes, I speak a little Spanish.",funFact:"From Late Latin 'fabulari' (to tell stories), cousin of English 'fable.' Spanish lost the f, softened b→b, and kept a verb that covers casual chat, lectures, and phone calls alike."},
        {type:"teach",trg:"estudiar",src:"to study",pos:"verb",gender:null,phonetic:"ehs-too-dee-AR",note:"-ar verb: estudio, estudias, estudia, estudiamos, estudian.",example:"A: ¿Dónde estudias?\nB: Estudio en la universidad.",exampleSrc:"A: Where do you study?\nB: I study at the university.",funFact:"From Latin 'studere' (to apply oneself zealously). Same root as English 'student,' 'studio,' 'studious.' The verb covers school study, examining a problem, and scrutinizing a painting."},
        {type:"teach",trg:"trabajar",src:"to work",pos:"verb",gender:null,phonetic:"trah-bah-HAR",note:"-ar verb: trabajo, trabajas, trabaja, trabajamos, trabajan.",example:"A: ¿Dónde trabajas?\nB: Trabajo en una oficina.",exampleSrc:"A: Where do you work?\nB: I work in an office.",funFact:"Etymologically grim: from Vulgar Latin 'tripaliare' (to torture with a three-stake instrument). Modern Spanish smoothed that to mean 'to work,' though the old pain is still visible in English 'travail.'"},
        {type:"teach",trg:"comprar",src:"to buy",pos:"verb",gender:null,phonetic:"kohm-PRAR",note:"-ar verb: compro, compras, compra, compramos, compran.",example:"A: ¿Qué compras en el supermercado?\nB: Compro fruta y leche.",exampleSrc:"A: What do you buy at the supermarket?\nB: I buy fruit and milk.",funFact:"From Latin 'comparare' (to make ready, equal up). The shopping sense emerged in Late Latin. Same root as English 'compare,' since buying once meant matching price to value."},
        {type:"teach",trg:"escuchar",src:"to listen",pos:"verb",gender:null,phonetic:"ehs-koo-CHAR",note:"-ar verb: escucho, escuchas, escucha, escuchamos, escuchan.",example:"A: ¿Escuchas música?\nB: Sí, escucho música todos los días.",exampleSrc:"A: Do you listen to music?\nB: Yes, I listen to music every day.",funFact:"From Latin 'auscultare' (to listen attentively), also the source of medical 'auscultation.' Spanish lost the initial vowel, kept the intensive sense."},
        {type:"tip",title:"-ar Verb Endings",text:"Remove -ar, add these endings:\nyo: -o (hablo)\ntú: -as (hablas)\nél/ella: -a (habla)\nnosotros: -amos (hablamos)\nellos/ellas: -an (hablan)\n\n-ar verbs are the LARGEST group in Spanish.\nAbout 80% of all Spanish verbs are -ar!",icon:"📝"},
        {type:"mc",q:"What is the 'nosotros' form of hablar?",opts:["hablamos","hablais","hablan","hablo"],ans:"hablamos",hint:"Nosotros always gets the -amos ending for -ar verbs."},
        {type:"fb",opts:["trabaja","trabajo","trabajas","trabajamos"],hint:"She works. Third person singular of an -ar verb.",s:"Ella {1} en un hospital.",a:"trabaja"},
        {type:"match",pairs:[{trg:"hablo",src:"I speak"},{trg:"estudias",src:"you study"},{trg:"trabaja",src:"he/she works"},{trg:"compramos",src:"we buy"},{trg:"escuchan",src:"they listen"}]},
        {type:"mc",q:"About what percentage of Spanish verbs are -ar?",opts:["About 50%","About 80%","About 30%","About 95%"],ans:"About 80%",hint:"The vast majority of Spanish verbs belong to this group."},
        {type:"fb",opts:["Hablas","Hablo","Habla","Hablamos"],hint:"Asking 'you' (tú) if you speak Spanish.",s:"¿{1} español?",a:"Hablas"},
        {type:"mc",q:"Complete: 'Nosotros ___ fruta en el mercado.'",opts:["compro","compran","compramos","compras"],ans:"compramos",hint:"We buy. Nosotros + -ar verb = -amos ending."},
        {type:"drag_fill",hint:"I study (yo) and she listens (ella).",s:"Yo {1} español y mi hermana {2} música.",blanks:{"1":"estudio","2":"escucha"},pool:["estudio","escucha","estudia","escucho","estudiamos","escuchamos"]},
        {type:"fb",opts:["compran","compra","compro","compramos"],hint:"They buy. Third person plural of comprar.",s:"Ellos {1} en el supermercado los sábados.",a:"compran"},
        {type:"mc",q:"Translate: 'We work in the morning and study at night.'",opts:["Trabajas por la mañana y estudias por la noche","Trabajan por la mañana y estudian por la noche","Trabajo por la mañana y estudio por la noche","Trabajamos por la mañana y estudiamos por la noche"],ans:"Trabajamos por la mañana y estudiamos por la noche",hint:"We = nosotros. Both verbs need -amos ending."},
        {type:"fb",opts:["compra","compro","compras","compran"],hint:"Third person singular of a regular -ar verb. Subject is ella.",s:"Mi madre {1} en el supermercado.",a:"compra"},
        {type:"mc",q:"What ending does 'yo' get with -ar verbs?",opts:["-o","-as","-a","-amos"],ans:"-o",hint:"The first person singular always ends in this letter."}
  ]},
  {id:"esp5l3",title:"Actividades Diarias",icon:"📋",xp:15,board:true,steps:[
        {type:"intro",title:"Actividades Diarias",desc:"Learn more daily activities with -er/-ir verbs and irregulars.",goals:["Use leer, escribir, dormir","Understand stem changes (o to ue)","Use ir (to go)"]},
        {type:"teach",trg:"leer",src:"to read",pos:"verb",gender:null,phonetic:"leh-ER",note:"-er verb: leo, lees, lee, leemos, leen.",example:"A: ¿Qué lees?\nB: Leo un libro muy interesante.",exampleSrc:"A: What are you reading?\nB: I'm reading a very interesting book.",funFact:"Leer has two vowels meeting (e-e). In the third-person preterite, an 'i' between vowels becomes 'y': leyó, leyeron. The same pattern applies to oír and caer."},
        {type:"teach",trg:"escribir",src:"to write",pos:"verb",gender:null,phonetic:"ehs-kree-BEER",note:"-ir verb: escribo, escribes, escribe, escribimos, escriben.",example:"A: ¿Escribes un diario?\nB: Sí, escribo un poco cada noche.",exampleSrc:"A: Do you write a diary?\nB: Yes, I write a little each night.",funFact:"Escribir has an irregular past participle 'escrito' (not 'escribido'), joining a small family: decir→dicho, hacer→hecho, ver→visto. These fossil forms come straight from Latin."},
        {type:"teach",trg:"dormir",src:"to sleep",pos:"verb",gender:null,phonetic:"dor-MEER",note:"Stem-changing (o to ue): duermo, duermes, duerme, dormimos, duermen.",example:"A: ¿Cuántas horas duermes?\nB: Duermo ocho horas.",exampleSrc:"A: How many hours do you sleep?\nB: I sleep eight hours.",funFact:"Dormir belongs to the e→ie and o→ue stem-changing family. The change only happens in stressed syllables, so 'nosotros dormimos' keeps the o (stress falls on the ending). Nicknamed 'boot verbs' for this pattern."},
        {type:"teach",trg:"ver",src:"to see / to watch",pos:"verb",gender:null,phonetic:"BER",note:"Irregular yo: veo. Rest regular: ves, ve, vemos, ven.",example:"A: ¿Qué ves en la tele?\nB: Veo una película española.",exampleSrc:"A: What do you watch on TV?\nB: I watch a Spanish movie.",funFact:"Ver is irregular throughout history: the Old Spanish infinitive was 'veer' (two e's). The modern imperfect keeps the old form: veía, veías. One of the fossil irregularities in Spanish."},
        {type:"teach",trg:"ir",src:"to go",pos:"verb",gender:null,phonetic:"EER",note:"Very irregular: voy, vas, va, vamos, van. One of the most used verbs!",example:"A: ¿Adónde vas?\nB: Voy al supermercado.",exampleSrc:"A: Where are you going?\nB: I'm going to the supermarket.",funFact:"Ir is a suppletive verb: its forms come from three different Latin verbs (ire, vadere, esse). The preterite 'fui/fuiste/fue' is shared with ser (to be), so context determines which verb is meant."},
        {type:"tip",title:"Stem-Changing Verbs: o to ue",text:"Some verbs change o to ue in stressed forms:\ndormir: duermo, duermes, duerme, dormimos, duermen\n\nNote: nosotros does NOT change!\nThe stress falls on the ending, not the stem.\n\nOther o to ue verbs: poder (puedo), volver (vuelvo).",icon:"📝"},
        {type:"mc",q:"What is the 'yo' form of dormir?",opts:["duermo","dormo","durmo","dormio"],ans:"duermo",hint:"The o in the stem changes to ue when stressed."},
        {type:"fb",opts:["va","voy","vas","vamos"],hint:"She goes. Third person singular of ir.",s:"Ella {1} al trabajo en autobús.",a:"va"},
        {type:"match",pairs:[{trg:"leo",src:"I read"},{trg:"escribes",src:"you write"},{trg:"duerme",src:"he/she sleeps"},{trg:"vemos",src:"we see"},{trg:"van",src:"they go"}]},
        {type:"mc",q:"Why doesn't 'dormimos' change the stem?",opts:["Nosotros forms never change","The stress is on the ending, not the stem","It's an exception to the rule","Both dormimos and duermimos work"],ans:"The stress is on the ending, not the stem",hint:"___ changes only happen in ___ed syllables."},
        {type:"fb",opts:["vas","voy","va","vamos"],hint:"Asking 'where are you going?' to one person (tú).",s:"¿Adónde {1}?",a:"vas"},
        {type:"mc",q:"Translate: 'I watch TV at night.'",opts:["Leo la tele por la noche","Voy la tele por la noche","Veo la tele por la noche","Ver la tele por la noche"],ans:"Veo la tele por la noche",hint:"___ = I watch/see. Irregular yo form of ver."},
        {type:"drag_fill",hint:"At night I read and then I sleep.",s:"Por la noche {1} un libro y después {2} ocho horas.",blanks:{"1":"leo","2":"duermo"},pool:["leo","duermo","lees","duermes","veo","voy"]},
        {type:"fb",opts:["vamos","van","voy","vas"],hint:"We go. Nosotros form of ir.",s:"Nosotros {1} al parque los domingos.",a:"vamos"},
        {type:"mc",q:"Which verb is stem-changing (o to ue)?",opts:["ir","escribir","leer","dormir"],ans:"dormir",hint:"This verb changes its root vowel in stressed forms."},
        {type:"fb",opts:["ves","veo","ve","ver"],hint:"Asking what YOU (tú) watch on TV.",s:"¿Qué {1} en la tele?",a:"ves"},
        {type:"mc",q:"Complete: 'Nosotros ___ al cine los viernes.'",opts:["vamos","van","voy","ir"],ans:"vamos",hint:"We go. Nosotros form of ir."}
  ]},
  {id:"esp5l4",title:"Verbos Reflexivos",icon:"🪞",xp:15,board:true,steps:[
        {type:"intro",title:"Verbos Reflexivos",desc:"Practice more reflexive verbs for daily routines.",goals:["Use 4 new reflexive verbs","Place pronouns correctly","Use articles with body parts"]},
        {type:"teach",trg:"lavarse",src:"to wash (oneself)",pos:"verb",gender:null,phonetic:"lah-BAR-seh",note:"Me lavo, te lavas, se lava, nos lavamos, se lavan.",example:"A: ¿Te lavas las manos antes de comer?\nB: Sí, siempre me lavo las manos.",exampleSrc:"A: Do you wash your hands before eating?\nB: Yes, I always wash my hands.",funFact:"Reflexive from 'lavar' (to wash). Body-part construction: 'me lavo las manos' (I wash my hands); NOT 'mis manos.' The article replaces the possessive for body parts."},
        {type:"teach",trg:"peinarse",src:"to comb one's hair",pos:"verb",gender:null,phonetic:"pay-NAR-seh",note:"Me peino, te peinas, se peina. Regular -ar reflexive.",example:"A: ¿Te peinas después de ducharte?\nB: Sí, me peino y me visto.",exampleSrc:"A: Do you brush your hair after showering?\nB: Yes, I brush my hair and get dressed.",funFact:"Reflexive from 'peinar' (to comb). Always with body-part article: 'me peino el pelo' (I comb my hair). 'Mi pelo' would sound off in standard Spanish."},
        {type:"teach",trg:"acostarse",src:"to go to bed",pos:"verb",gender:null,phonetic:"ah-kohs-TAR-seh",note:"Stem-changing (o to ue): me acuesto, te acuestas, se acuesta.",example:"A: ¿A qué hora te acuestas?\nB: Me acuesto a las once.",exampleSrc:"A: What time do you go to bed?\nB: I go to bed at eleven.",funFact:"Reflexive + o→ue stem change. 'Me acuesto' (I lie down / go to bed). From 'costa' (side/edge); originally 'to put oneself on one's side.'"},
        {type:"teach",trg:"sentarse",src:"to sit down",pos:"verb",gender:null,phonetic:"sen-TAR-seh",note:"Stem-changing (e to ie): me siento, te sientas, se sienta.",example:"A: ¿Puedo sentarse aquí?\nB: Sí, puedes sentarse.",exampleSrc:"A: Can I sit down here?\nB: Yes, you can sit down.",funFact:"Reflexive + e→ie stem change. 'Me siento' (I sit down). Don't confuse with 'sentirse' (to feel): 'me siento triste' (I feel sad). Spelled identically in yo form; context decides."},
        {type:"teach",trg:"cepillarse los dientes",src:"to brush one's teeth",pos:"verb",gender:null,phonetic:"seh-pee-YAR-seh lohs dee-EN-tehs",note:"Me cepillo, te cepillas, se cepilla. Use LOS dientes, not MIS.",example:"A: ¿Cuántas veces te cepillas los dientes?\nB: Me cepillo los dientes tres veces al día.",exampleSrc:"A: How many times do you brush your teeth?\nB: I brush my teeth three times a day.",funFact:"Full body-care phrase. 'Cepillarse' (brush oneself) + 'los dientes' (the teeth). Again: definite article with body parts, not possessive."},
        {type:"tip",title:"Reflexive + Body Parts",text:"With reflexive verbs, use THE article (not possessive) for body parts:\nMe lavo LAS manos. (not mis manos)\nMe cepillo LOS dientes. (not mis dientes)\nSe peina EL pelo. (not su pelo)\n\nThe reflexive pronoun already shows whose body it is.",icon:"💡"},
        {type:"mc",q:"How do you say 'I go to bed at ten'?",opts:["Me acuesto a las diez","Me acosto a las diez","Acuesto me a las diez","Me acuesta a las diez"],ans:"Me acuesto a las diez",hint:"Stem change o to ue: acostarse becomes me ___."},
        {type:"fb",opts:["se","me","te","nos"],hint:"Third person reflexive pronoun.",s:"Ella {1} sienta en el sofá.",a:"se"},
        {type:"match",pairs:[{trg:"me lavo",src:"I wash"},{trg:"te peinas",src:"you comb"},{trg:"se acuesta",src:"he/she goes to bed"},{trg:"nos sentamos",src:"we sit down"},{trg:"se cepillan",src:"they brush"}]},
        {type:"mc",q:"'Me cepillo LOS dientes' (not MIS dientes) because:",opts:["It's a grammar exception with no logic","The reflexive pronoun already shows ownership","Both forms are correct in all cases","Los sounds better than mis here"],ans:"The reflexive pronoun already shows ownership",hint:"The me ___ tells us whose teeth they are."},
        {type:"fb",opts:["acuestas","acuesto","acuesta","acostamos"],hint:"Asking what time YOU (tú) go to bed.",s:"¿A qué hora te {1}?",a:"acuestas"},
        {type:"mc",q:"Which verb has the stem change e to ie?",opts:["peinarse","lavarse","sentarse","cepillarse"],ans:"sentarse",hint:"Me siento, te sientas. The e in sent- changes."},
        {type:"drag_fill",hint:"I wash my hands and then brush my teeth.",s:"Yo {1} {2} las manos y después {3} {4} los dientes.",blanks:{"1":"me","2":"lavo","3":"me","4":"cepillo"},pool:["me","lavo","me","cepillo","se","peino"]},
        {type:"fb",opts:["sentamos","sentimos","siento","sientan"],hint:"We sit down. Nosotros form has no stem change.",s:"Nosotros nos {1} en el sofá para ver la tele.",a:"sentamos"},
        {type:"mc",q:"Translate: 'She combs her hair every morning.'",opts:["Peina se todas las mañanas","Me peino todas las mañanas","Se peina todos las mañanas","Se peina todas las mañanas"],ans:"Se peina todas las mañanas",hint:"Se = she (reflexive). ___ las ___ = every morning."},
        {type:"fb",opts:["cepillo","cepillas","lavo","peino"],hint:"First person of the verb for teeth brushing.",s:"Me {1} los dientes tres veces al día.",a:"cepillo"},
        {type:"mc",q:"'Me acuesto a las once' means:",opts:["I go to bed at eleven","I wake up at eleven","I get dressed at eleven","I shower at eleven"],ans:"I go to bed at eleven",hint:"Acostarse = to go to b.... The last action of the day."}
  ]},
  {id:"esp5l5",title:"El Orden del Día",icon:"📅",xp:15,board:true,steps:[
        {type:"intro",title:"El Orden del Día",desc:"Use sequence words to describe your daily routine in order.",goals:["Use primero, luego, después, finalmente","Combine time with activities","Describe a full day"]},
        {type:"teach",trg:"primero",src:"first",pos:"adj",gender:null,phonetic:"pree-MEH-roh",note:"Sequence word. Placed at the start of the sentence.",example:"A: ¿Qué haces por la mañana?\nB: Primero me despierto a las siete.",exampleSrc:"A: What do you do in the morning?\nB: First I wake up at seven.",funFact:"First. Ordinal number. Apocopes to 'primer' before masculine singular: 'el primer dia' (the first day). But 'la primera vez' (the first time) keeps full form."},
        {type:"teach",trg:"luego / después",src:"then / after",pos:"intj",gender:null,phonetic:"LWEH-goh / des-PWEHS",note:"Luego and después are interchangeable. Both mean 'then/after'.",example:"A: ¿Y después?\nB: Luego me ducho y después desayuno.",exampleSrc:"A: And then?\nB: Then I shower and after that I have breakfast.",funFact:"Both mean 'then/later.' 'Luego' is slightly quicker in feel, 'después' has more distance. In narration, Spanish speakers chain both: 'primero, luego, después, finalmente.'"},
        {type:"teach",trg:"antes de",src:"before",pos:"verb",gender:null,phonetic:"AHN-tes deh",note:"Antes de + infinitive: before doing something.",example:"A: ¿Te duchas antes de desayunar?\nB: Sí, siempre antes de desayunar.",exampleSrc:"A: Do you shower before having breakfast?\nB: Yes, always before having breakfast.",funFact:"Preposition + infinitive. 'Antes de comer' (before eating). Never 'antes de comiendo.' Spanish prefers infinitive after prepositions where English uses -ing."},
        {type:"teach",trg:"después de",src:"after (doing)",pos:"verb",gender:null,phonetic:"des-PWEHS deh",note:"Después de + infinitive: after doing something.",example:"A: ¿Qué haces después de trabajar?\nB: Después de trabajar voy al gimnasio.",exampleSrc:"A: What do you do after work?\nB: After working I go to the gym.",funFact:"Same pattern. 'Después de comer' (after eating). 'Después de comer, salimos'; after eating, we went out. Infinitive, not gerund."},
        {type:"teach",trg:"finalmente",src:"finally",pos:"adv",gender:null,phonetic:"fee-nahl-MEN-teh",note:"Used to mark the last action in a sequence.",example:"A: ¿Y al final del día?\nB: Finalmente me acuesto a las once.",exampleSrc:"A: And at the end of the day?\nB: Finally I go to bed at eleven.",funFact:"Finally. Adverb. Formed by adding -mente to the feminine adjective 'final' (which happens to be the same masc/fem). The Spanish adverb suffix -mente = English -ly."},
        {type:"tip",title:"Building a Routine Description",text:"Use this pattern:\nPrimero + activity + time.\nLuego/Después + activity.\nDespués de + infinitive + next activity.\nFinalmente + last activity.\n\nExample:\nPrimero me levanto a las siete.\nLuego me ducho.\nDespués de desayunar, voy al trabajo.\nFinalmente me acuesto a las once.",icon:"📝"},
        {type:"mc",q:"Which word means 'before'?",opts:["antes de","después de","luego","finalmente"],ans:"antes de",hint:"The opposite of después de. Something that happens first."},
        {type:"fb",opts:["Primero","Después","Finalmente","Luego"],hint:"The first action in a sequence gets this word.",s:"{1} me despierto y luego me levanto.",a:"Primero"},
        {type:"match",pairs:[{trg:"primero",src:"first"},{trg:"luego",src:"then"},{trg:"después de",src:"after"},{trg:"antes de",src:"before"},{trg:"finalmente",src:"finally"}]},
        {type:"mc",q:"'Después de comer, leo un libro' means:",opts:["Before eating, I read a book","After eating, I read a book","While eating, I read a book","Instead of eating, I read a book"],ans:"After eating, I read a book",hint:"Comer is the infinitive for the first action. Después de is the opposite of antes de."},
        {type:"fb",opts:["antes","después","primero","luego"],hint:"You shower BEFORE eating breakfast, not after.",s:"Me ducho {1} de desayunar.",a:"antes"},
        {type:"mc",q:"Which sentence is in the correct order?",opts:["Luego me levanto, finalmente me ducho, primero desayuno","Finalmente me levanto, primero me ducho, luego desayuno","Primero me levanto, luego me ducho, finalmente desayuno","Después me levanto, antes me ducho, primero desayuno"],ans:"Primero me levanto, luego me ducho, finalmente desayuno",hint:"First = ___, then = ___, last = ___."},
        {type:"drag_fill",hint:"Order: first, then, after getting dressed.",s:"{1} me despierto. {2} me ducho. {3} de vestirme, desayuno.",blanks:{"1":"Primero","2":"Luego","3":"Después"},pool:["Primero","Luego","Después","Antes","Finalmente","Por"]},
        {type:"fb",opts:["Después","Antes","Primero","Luego"],hint:"You read AFTER eating, not before.",s:"{1} de comer, leo un libro.",a:"Después"},
        {type:"mc",q:"Translate: 'Finally I go to bed at eleven.'",opts:["Antes me acuesto a las once","Primero me acuesto a las once","Después me acuesto a las once","Finalmente me acuesto a las once"],ans:"Finalmente me acuesto a las once",hint:"The last action of the day uses this sequence word."},
        {type:"fb",opts:["mañana","noche","tarde","hora"],hint:"The first part of the day, before afternoon.",s:"Estudio por la {1} y trabajo por la tarde.",a:"mañana"},
        {type:"mc",q:"What comes after 'antes de' or 'después de'?",opts:["An infinitive verb","A conjugated verb","A noun only","An adjective"],ans:"An infinitive verb",hint:"Before/after DOING something uses the base form."}
  ]},
  {id:"esp5l6",title:"¿A Qué Hora?",icon:"⏰",xp:15,board:true,steps:[
        {type:"intro",title:"¿A Qué Hora?",desc:"Combine time expressions with daily activities.",goals:["Ask and answer 'at what time?'","Use frequency words","Schedule activities throughout the day"]},
        {type:"teach",trg:"¿a qué hora?",src:"at what time?",pos:"intj",gender:null,phonetic:"ah keh OH-rah",note:"Always 'a las' + hour (except 1:00 = a la una).",example:"A: ¿A qué hora te levantas?\nB: Me levanto a las siete y media.",exampleSrc:"A: At what time do you get up?\nB: I get up at seven thirty.",funFact:"Literally 'at what hour.' Spanish time questions always use 'hora' (not 'tiempo,' which means weather or abstract time). '¿Qué hora es?' asks the clock; '¿a qué hora?' asks when something happens."},
        {type:"teach",trg:"a las + hora",src:"at + time",pos:"intj",gender:null,phonetic:"ah lahs",note:"A la una (1:00), a las dos, a las tres... Always a las for 2+.",example:"A: ¿Cuándo comes?\nB: Como a las dos de la tarde.",exampleSrc:"A: When do you eat?\nB: I eat at two in the afternoon.",funFact:"Preposition 'a' + article 'las' + number. Plural 'las' because the implied noun is 'horas.' Singular only for one o'clock ('a la una')."},
        {type:"teach",trg:"temprano",src:"early",pos:"adj",gender:null,phonetic:"tem-PRAH-noh",note:"Opposite: tarde (late). Muy temprano = very early.",example:"A: ¿Te levantas temprano?\nB: Sí, me levanto muy temprano, a las cinco.",exampleSrc:"A: Do you get up early?\nB: Yes, I get up very early, at five.",funFact:"Early. Adverb (invariable). From Latin 'temporaneus' (timely). 'Me levanto temprano'; I wake up early. Opposite: 'tarde' (late)."},
        {type:"teach",trg:"tarde",src:"late",pos:"verb",gender:null,phonetic:"TAR-deh",note:"Tarde = late (adverb) or afternoon (noun). Context matters!",example:"A: ¿Por qué llegas tarde?\nB: Porque me levanto tarde.",exampleSrc:"A: Why are you arriving late?\nB: Because I get up late.",funFact:"Adverb 'late.' Invariable. 'Llego tarde' (I arrive late). Don't confuse with 'la tarde' (afternoon, noun); same spelling, different category."},
        {type:"teach",trg:"siempre / nunca",src:"always / never",pos:"adv",gender:null,phonetic:"see-EM-preh / NOON-kah",note:"Siempre = always. Nunca = never. Go before the verb.",example:"A: ¿Siempre desayunas?\nB: No, nunca desayuno. No tengo hambre.",exampleSrc:"A: Do you always have breakfast?\nB: No, I never have breakfast. I'm not hungry.",funFact:"Frequency adverbs. Note: with 'nunca' before the verb, no 'no' needed. 'Nunca voy' = 'I never go.' Double negative 'no voy nunca' is also correct (emphatic)."},
        {type:"tip",title:"Frequency Words",text:"Common frequency words:\nsiempre = always\ncasi siempre = almost always\na veces = sometimes\ncasi nunca = almost never\nnunca = never\n\nPlacement: usually BEFORE the verb.\nSiempre me levanto temprano.\nNunca como pescado.",icon:"📝"},
        {type:"mc",q:"How do you say 'at two o'clock'?",opts:["a las dos","a la dos","en las dos","por las dos"],ans:"a las dos",hint:"For hours 2+, use 'a las'. Only 1:00 uses 'a la'."},
        {type:"fb",opts:["hora","tiempo","día","vez"],hint:"Asking 'at what ___?' when asking about the time of an action.",s:"¿A qué {1} te acuestas?",a:"hora"},
        {type:"match",pairs:[{trg:"siempre",src:"always"},{trg:"a veces",src:"sometimes"},{trg:"nunca",src:"never"},{trg:"temprano",src:"early"},{trg:"tarde",src:"late"}]},
        {type:"mc",q:"'Nunca como pescado' means:",opts:["I always eat fish","I never eat fish","I sometimes eat fish","I eat fish late"],ans:"I never eat fish",hint:"Nunca is the opposite of siempre. Como = first person singular of comer."},
        {type:"fb",opts:["siempre","nunca","tarde","hora"],hint:"I get up at 5 AM every single day without exception.",s:"Me levanto {1} a las cinco de la mañana.",a:"siempre"},
        {type:"mc",q:"What time expression means 'at 1:00'?",opts:["a la uno","a las una","a la una","a el una"],ans:"a la una",hint:"One o'clock is the exception. Use singular 'la' instead of 'las'."},
        {type:"drag_fill",hint:"I always get up early but today I'm getting up late.",s:"{1} me levanto {2} pero hoy me levanto {3} a las {4}.",blanks:{"1":"Siempre","2":"temprano","3":"tarde","4":"diez"},pool:["Siempre","temprano","tarde","diez","Nunca","ocho"]},
        {type:"fb",opts:["veces","siempre","nunca","vamos"],hint:"Not always, not never, but occasionally.",s:"A {1} como en un restaurante.",a:"veces"},
        {type:"mc",q:"Translate: 'I always shower in the morning.'",opts:["Siempre ducho me por la mañana","Nunca me ducho por la mañana","Me ducho siempre la mañana","Siempre me ducho por la mañana"],ans:"Siempre me ducho por la mañana",hint:"___ before the reflexive pronoun + verb."},
        {type:"fb",opts:["temprano","tarde","nunca","siempre"],hint:"Getting up early on Monday mornings.",s:"Me levanto {1} los lunes.",a:"temprano"},
        {type:"mc",q:"What does 'casi nunca' mean?",opts:["almost never","almost always","sometimes","never ever"],ans:"almost never",hint:"Casi = ___. Nunca = ___. Combined together."}
  ]},
  {id:"esp5l7",title:"El Fin de Semana",icon:"🎉",xp:15,board:true,steps:[
        {type:"intro",title:"El Fin de Semana",desc:"Talk about weekend activities and free time.",goals:["Describe weekend plans","Use ir + a + place","Combine activities with locations"]},
        {type:"teach",trg:"el fin de semana",src:"the weekend",pos:"noun",gender:"m",phonetic:"el feen deh seh-MAH-nah",note:"Masculine. Plural: los fines de semana.",example:"A: ¿Qué haces los fines de semana?\nB: Los fines de semana descanso.",exampleSrc:"A: What do you do on weekends?\nB: On weekends I rest.",funFact:"Weekend. Literally 'end of the week.' Plural: los fines de semana. Note: 'fin' stays singular; 'semana' stays singular. Just 'fines' pluralizes."},
        {type:"teach",trg:"descansar",src:"to rest",pos:"verb",gender:null,phonetic:"des-kahn-SAR",note:"Regular -ar verb: descanso, descansas, descansa.",example:"A: ¿Descansas los domingos?\nB: Sí, los domingos descanso en casa.",exampleSrc:"A: Do you rest on Sundays?\nB: Yes, on Sundays I rest at home.",funFact:"From 'des-' + 'cansar' (to tire). Literally 'to un-tire.' Spanish has the opposite construction too: 'cansarse' (to get tired). Both verbs anchor the rest/fatigue axis."},
        {type:"teach",trg:"jugar",src:"to play",pos:"verb",gender:null,phonetic:"hoo-GAR",note:"Stem-changing (u to ue): juego, juegas, juega, jugamos, juegan. Uses a + el = al.",example:"A: ¿Juegas al fútbol?\nB: Sí, juego al fútbol los sábados.",exampleSrc:"A: Do you play football?\nB: Yes, I play football on Saturdays.",funFact:"One of the few -ar verbs with a u→ue stem change: juego, juegas, juega. From Latin 'iocare' (to joke, play), same root as English 'joke' and 'jocular.' Games and jokes share an origin."},
        {type:"teach",trg:"ir al parque",src:"to go to the park",pos:"verb",gender:null,phonetic:"eer al PAR-keh",note:"Ir + al (a + el) + place. Ir + a la + feminine place.",example:"A: ¿Adónde vais este domingo?\nB: Vamos al parque con los niños.",exampleSrc:"A: Where are you going this Sunday?\nB: We're going to the park with the kids.",funFact:"Ir + a + place. 'Al' is mandatory contraction of a + el. 'Voy a el parque' is wrong; always 'voy al parque.' Spanish permits no leading preposition stranding."},
        {type:"teach",trg:"pasear",src:"to go for a walk",pos:"verb",gender:null,phonetic:"pah-seh-AR",note:"Regular -ar verb: paseo, paseas, pasea. Pasear al perro = walk the dog.",example:"A: ¿Te gusta pasear?\nB: Sí, paseo por el centro los domingos.",exampleSrc:"A: Do you like to walk?\nB: Yes, I walk around the center on Sundays.",funFact:"From 'paso' (step), related to English 'pace.' The reflexive 'pasearse' means to stroll; the transitive 'pasear al perro' means to walk the dog. A daily ritual in Spanish culture."},
        {type:"tip",title:"Ir + a + Place",text:"Use ir to talk about going places:\nVoy al parque. (a + el = al)\nVoy a la playa. (a + la stays)\nVoy a casa. (no article with casa)\n\nir: voy, vas, va, vamos, van\n\nVamos = let's go! (very common)",icon:"📝"},
        {type:"mc",q:"What is the stem change in jugar?",opts:["u to ue","o to ue","e to ie","e to i"],ans:"u to ue",hint:"Juego, juegas, juega. The u in jug- changes."},
        {type:"fb",opts:["juego","jugo","juegas","jugamos"],hint:"I play. First person singular with stem change.",s:"Los sábados {1} al fútbol.",a:"juego"},
        {type:"match",pairs:[{trg:"descansar",src:"to rest"},{trg:"jugar",src:"to play"},{trg:"pasear",src:"to walk"},{trg:"ver la tele",src:"to watch TV"},{trg:"ir al parque",src:"to go to the park"}]},
        {type:"mc",q:"How do you say 'Let's go!'?",opts:["¡Voy!","¡Vamos!","¡Van!","¡Vas!"],ans:"¡Vamos!",hint:"The nosotros form of ir doubles as 'let's go'."},
        {type:"fb",opts:["Vamos","Voy","Van","Vas"],hint:"Suggesting we go to the cinema. Let's go!",s:"¿{1} al cine este sábado?",a:"Vamos"},
        {type:"mc",q:"Complete: 'Mi padre ___ por el parque todas las tardes.'",opts:["paseas","paseo","pasea","paseamos"],ans:"pasea",hint:"My father (él) walks. Third person singular."},
        {type:"drag_fill",hint:"On weekends I go to the park and then watch TV.",s:"Los fines de semana {1} al {2} y después {3} la {4}.",blanks:{"1":"voy","2":"parque","3":"veo","4":"tele"},pool:["voy","parque","veo","tele","juego","fútbol"]},
        {type:"fb",opts:["descanso","descansas","descansa","descansamos"],hint:"I rest on Sundays. First person singular.",s:"Los domingos {1} en casa.",a:"descanso"},
        {type:"mc",q:"Translate: 'We play football on Saturdays.'",opts:["Juegas al fútbol los sábados","Juegan al fútbol los sábados","Juego al fútbol los sábados","Jugamos al fútbol los sábados"],ans:"Jugamos al fútbol los sábados",hint:"We = nosotros. No stem change in nosotros form: ___."},
        {type:"fb",opts:["pasear","paseamos","paseas","pasea"],hint:"After me gusta, use the infinitive form.",s:"Los fines de semana me gusta {1}.",a:"pasear"},
        {type:"mc",q:"'Voy a la playa' uses 'a la' because:",opts:["Playa is feminine","Playa is masculine","We always use a la","It's a contraction"],ans:"Playa is feminine",hint:"A + la stays as two words. Only a + el becomes al."}
  ]},
  {id:"esp5l8c",title:"Los Sentimientos",icon:"😊",xp:22,board:true,steps:[
        {type:"intro",title:"Los Sentimientos",desc:"How do you feel? Happy, sad, tired, nervous? In Spanish, you use estar + adjective for emotions. Learn to express how you and others feel.",goals:["Learn 14 emotion words with gender forms","Use estar + emotion (not ser)","Understand ser vs estar with feelings"]},
        {type:"tip",title:"Estar + Emotion",deepDive:{
          title:"Ser vs Estar with emotions",
          text:"Estar = how you feel RIGHT NOW (temporary).\nEstoy feliz. = I am happy (at this moment).\n\nSer = what you are LIKE as a person (permanent).\nSoy feliz. = I am a happy person (in general).\n\nMost emotions use estar because feelings come and go.\nOnly use ser when describing personality."
        },text:"For TEMPORARY feelings, use estar:\nEstoy triste. = I am sad (right now).\nEstá cansado. = He is tired (right now).\nEstamos nerviosos. = We are nervous.\n\nThe adjective must agree with the subject:\nÉl está cansadO.\nElla está cansadA.\nEllos están cansadOS.\nEllas están cansadAS."},
        {type:"teach",trg:"contento / contenta",src:"happy, pleased",pos:"intj",gender:null,note:"Contento (masc), contenta (fem).\nSimilar to feliz, but more casual.\nEstoy contento = I am pleased.",example:"A: ¿Estás contento con tu nota?\nB: Sí, estoy muy contento.\nA: ¡Enhorabuena!",exampleSrc:"A: Are you happy with your grade?\nB: Yes, I am very happy.\nA: Congratulations!",funFact:"Milder than 'feliz' (happy). 'Contento' is situational contentment; 'feliz' is deeper happiness. Use 'estar contento' (state), not 'ser.'"},
        {type:"teach",trg:"triste",src:"sad",pos:"noun",gender:"m",note:"Triste = sad. Same for masc and fem.\nPlural: tristes.\nEstoy triste, estás triste...",example:"A: ¿Por qué estás triste?\nB: Estoy triste porque mi amigo se fue.\nA: Lo siento mucho.",exampleSrc:"A: Why are you sad?\nB: I am sad because my friend left.\nA: I am very sorry.",funFact:"Sad. Invariable for gender: el hombre triste, la mujer triste. From Latin 'tristis.' Same root as English 'tristful.' Plural: tristes."},
        {type:"teach",trg:"enfadado / enfadada",src:"angry",pos:"intj",gender:null,note:"Enfadado (masc), enfadada (fem).\nIn Latin America: enojado/enojada.\nConmigo = with me, contigo = with you.",example:"A: ¿Estás enfadado conmigo?\nB: No, no estoy enfadado contigo.\nA: ¡Menos mal!",exampleSrc:"A: Are you angry with me?\nB: No, I am not angry with you.\nA: Thank goodness!",funFact:"Spain's standard word for angry. Latin America usually says 'enojado/a.' Both work everywhere, but using 'enfadado' in Mexico or 'enojado' in Madrid marks you as an outsider."},
        {type:"teach",trg:"cansado / cansada",src:"tired",pos:"adj",gender:null,note:"Cansado (masc), cansada (fem).\nMuy cansado = very tired.\nEstoy cansado de trabajar = I am tired of working.",example:"A: Estoy muy cansada hoy.\nB: ¿No dormiste bien?\nA: No, me acosté muy tarde.",exampleSrc:"A: I am very tired today.\nB: Did you not sleep well?\nA: No, I went to bed very late.",funFact:"From cansar (to tire). Always uses 'estar' not 'ser': 'estoy cansado' (I am tired right now), never 'soy cansado'. Ser + adjectives of physical state is a classic Spanish learner pitfall."},
        {type:"teach",trg:"nervioso / nerviosa",src:"nervous",pos:"intj",gender:null,note:"Nervioso (masc), nerviosa (fem).\nEstoy nervioso por = I am nervous about.",example:"A: Estoy muy nerviosa hoy.\nB: Tranquila. Estás bien.",exampleSrc:"A: I am very nervous today.\nB: Relax. You are fine.",funFact:"Uses estar ('estoy nervioso'), not ser. With 'ser,' it means habitually anxious as a personality trait. Tenso distinction matters for register."},
        {type:"teach",trg:"asustado / asustada",src:"scared, afraid",pos:"intj",gender:null,note:"Asustado (masc), asustada (fem).\nAraña = spider.\nTener miedo = to be afraid (alternative).",example:"A: ¿Estás asustado?\nB: Sí, estoy muy asustado. ¿Y tú?\nA: No, estoy tranquila.",exampleSrc:"A: Are you scared?\nB: Yes, I am very scared. And you?\nA: No, I am calm.",funFact:"Past participle of 'asustar' (to scare). The active verb is transitive: 'me asusta' (it scares me). 'Estar asustado' is the resulting state."},
        {type:"mc",q:"Ella está muy ___. (tired)",opts:["cansada","cansado","cansados","cansadas"],ans:"cansada",hint:"Ella is feminine singular. The adjective must match."},
        {type:"fb",opts:["nervioso","contento","cansado","triste"],hint:"Having an exam tomorrow causes worry and anxiety.",s:"Estoy {1} porque mañana tengo un examen.",a:"nervioso"},
        {type:"teach",trg:"preocupado / preocupada",src:"worried",pos:"intj",gender:null,note:"Preocupado (masc), preocupada (fem).\nPreocupados/preocupadas (plural).\nEstoy preocupado por = I am worried about.",example:"A: Mis padres están preocupados.\nB: ¿Por qué están preocupados?\nA: Porque llego tarde a casa.",exampleSrc:"A: My parents are worried.\nB: Why are they worried?\nA: Because I come home late.",funFact:"Literally 'pre-occupied'; mentally occupied in advance by something. Same Latin root as English, but Spanish kept the worry sense while English split off to mean busy."},
        {type:"teach",trg:"sorprendido / sorprendida",src:"surprised",pos:"intj",gender:null,note:"Sorprendido (masc), sorprendida (fem).\nRegalar = to give as a gift.",example:"A: ¡Estoy sorprendida!\nB: ¿Por qué?\nA: Estoy sorprendida por tu carta.",exampleSrc:"A: I am surprised!\nB: Why?\nA: I am surprised by your letter.",funFact:"Past participle of 'sorprender' (to surprise). Like other emotion adjectives, uses estar because it describes a current state, not a permanent trait."},
        {type:"teach",trg:"aburrido / aburrida",src:"bored",pos:"intj",gender:null,note:"Aburrido (masc), aburrida (fem).\nNada = nothing.\nNo hay nada = there is nothing.",example:"A: Estoy aburrido. ¿Y tú?\nB: Yo también estoy aburrida.",exampleSrc:"A: I am bored. And you?\nB: I am bored too.",funFact:"Classic ser/estar trap. 'Ser aburrido' = to be boring (a boring person). 'Estar aburrido' = to be bored (right now). Swap them and you insult yourself or someone else."},
        {type:"teach",trg:"emocionado / emocionada",src:"excited",pos:"intj",gender:null,note:"Emocionado (masc), emocionada (fem).\nEstoy emocionado por = I am excited about.\nViaje = trip.",example:"A: ¡Estoy muy emocionada por el viaje!\nB: ¿Adónde vas?\nA: Voy a Barcelona.",exampleSrc:"A: I am very excited about the trip!\nB: Where are you going?\nA: I am going to Barcelona.",funFact:"False friend alert: means 'excited,' not 'emotional.' For emotional in the English sense, Spanish uses 'sensible' or 'conmovido.'"},
        {type:"mc",q:"Los niños están ___. (bored)",opts:["aburrido","aburridos","aburrida","aburridas"],ans:"aburridos",hint:"Los niños is masculine plural. Match both gender and number."},
        {type:"fb",opts:["preocupada","preocupado","preocupados","preocupadas"],hint:"Mi madre is feminine singular. Worried about not calling.",s:"Mi madre está {1} porque no llamo.",a:"preocupada"},
        {type:"teach",trg:"orgulloso / orgullosa",src:"proud",pos:"intj",gender:null,note:"Orgulloso (masc), orgullosa (fem).\nOrgulloso de = proud of.\nAprobar = to pass (an exam).",example:"A: Mis padres están orgullosos de mí.\nB: ¿Por qué?\nA: Porque aprobé todos los exámenes.",exampleSrc:"A: My parents are proud of me.\nB: Why?\nA: Because I passed all the exams.",funFact:"Takes the preposition 'de': 'orgulloso de mi hija' (proud of my daughter). Unlike English, can also mean arrogant depending on context."},
        {type:"teach",trg:"solo / sola",src:"lonely, alone",pos:"intj",gender:null,note:"Solo (masc), sola (fem).\nSolo can mean 'alone' or 'lonely'.\nDe viaje = traveling.",example:"A: ¿Estás sola en casa?\nB: Sí, estoy sola. Mi familia está de viaje.\nA: ¿Quieres venir a cenar con nosotros?",exampleSrc:"A: Are you alone at home?\nB: Yes, I am alone. My family is traveling.\nA: Do you want to come have dinner with us?",funFact:"Adjective meaning alone, lonely, or single. The adverb 'sólo' (only) used to carry an accent but RAE dropped it in 2010. Context now disambiguates."},
        {type:"teach",trg:"avergonzado / avergonzada",src:"embarrassed",pos:"intj",gender:null,note:"Avergonzado (masc), avergonzada (fem).\nCaerse = to fall down.\nDelante de = in front of.",example:"A: Estoy avergonzado.\nB: ¿Qué pasó?\nA: Me caí delante de toda la clase.",exampleSrc:"A: I am embarrassed.\nB: What happened?\nA: I fell down in front of the whole class.",funFact:"From 'vergüenza' (shame). Long word, common typo. Uses estar for embarrassed. Never ser; 'ser avergonzado' would mean shameful as a personality."},
        {type:"mc",q:"Estoy ___ porque voy de vacaciones mañana.",opts:["triste","enfadado","emocionado","asustado"],ans:"emocionado",hint:"Going on vacation tomorrow makes you feel thrilled."},
        {type:"match",pairs:[{trg:"contento",src:"happy, pleased"},{trg:"triste",src:"sad"},{trg:"enfadado",src:"angry"},{trg:"nervioso",src:"nervous"},{trg:"cansado",src:"tired"},{trg:"asustado",src:"scared"}]},
        {type:"fb",opts:["orgullosa","orgulloso","orgullosos","orgullosas"],hint:"Ella is feminine singular. She is proud of her son.",s:"Ella está {1} de su hijo.",a:"orgullosa"},
        {type:"mc",q:"Which emotion word does NOT change for gender?",opts:["cansado","nervioso","enfadado","triste"],ans:"triste",hint:"This word ends in -e, not -o. It stays the same for everyone."},
        {type:"drag_fill",hint:"Hermana is feminine, hermano is masculine. Each adjective must agree.",s:"Mi hermana está {1} y mi hermano está {2}.",blanks:{"1":"contenta","2":"cansado"},pool:["contenta","cansado","contento","cansada"]},
        {type:"match",pairs:[
          {trg:"preocupado",src:"worried"},
          {trg:"sorprendida",src:"surprised (fem)"},
          {trg:"aburrido",src:"bored"},
          {trg:"emocionada",src:"excited (fem)"},
          {trg:"orgulloso",src:"proud"},
          {trg:"avergonzada",src:"embarrassed (fem)"}
        ]},
        {type:"mc",q:"'Estoy triste' vs 'Soy triste'. What is the difference?",opts:["Estoy = sad right now. Soy = a sad person by nature.","They mean the same thing.","Estoy is informal, soy is formal.","Estoy is wrong, only soy works."],ans:"Estoy = sad right now. Soy = a sad person by nature.",hint:"One verb describes a current state, the other a permanent trait."},
        {type:"fb",opts:["asustada","contenta","emocionada","orgullosa"],hint:"Something happened that frightened you. Using the feminine form.",s:"¿Por qué estás {1}? ¿Qué pasó?",a:"asustada"}
  ]},
  {id:"esp5l7b",title:"El día de Verumius",icon:"☀️",xp:10,board:true,steps:[
        {type:"intro",title:"El día de Verumius",desc:"Carmen asks Verumius about his daily routine. His answers are very... Roman.",goals:["See daily routine vocabulary in real conversation","Watch Verumius describe his day","Enjoy the story"]},
        {type:"story",speaker:"narrator",mood:"calm",art:"es-unit-05-scene-01",trg:"Carmen y Verumius pasean por el parque el domingo. Carmen pregunta sobre la rutina de Verumius.",src:"Carmen and Verumius walk in the park on Sunday. Carmen asks about Verumius's routine."},
        {type:"story",speaker:"carmen",mood:"curious",art:"es-unit-05-scene-01",trg:"Verumius, ¿a qué hora te despiertas por la mañana?",src:"Verumius, at what time do you wake up in the morning?"},
        {type:"story",speaker:"verumius",mood:"proud",art:"es-unit-05-scene-02",trg:"Primero me despierto a las cinco. Luego leo libros. Después estudio español. Siempre.",src:"First I wake up at five. Then I read books. After that I study Spanish. Always."},
        {type:"story",speaker:"carmen",mood:"surprised",art:"es-unit-05-scene-02",trg:"¡Las cinco! ¿Y a qué hora te acuestas?",src:"Five o'clock! And at what time do you go to bed?"},
        {type:"story",speaker:"verumius",mood:"confused",art:"es-unit-05-scene-03",trg:"Me acuesto a las nueve de la noche. ¿Es tarde? En Roma, los romanos se acuestan a las nueve.",src:"I go to bed at nine at night. Is that late? In Rome, Romans go to bed at nine."},
        {type:"story",speaker:"carmen",mood:"laughing",art:"es-unit-05-scene-03",trg:"¡Verumius! En Madrid, ¡las nueve de la noche es la hora de cenar!",src:"Verumius! In Madrid, nine at night is dinner time!"}
  ]},
  {id:"esp5l8",title:"Un Día Típico",icon:"📖",xp:15,board:true,steps:[
        {type:"intro",title:"Un Día Típico",desc:"Describe a complete typical day from morning to night.",goals:["Combine all unit vocabulary","Use sequence words naturally","Describe routines fluently"]},
        {type:"mc",q:"How do you say 'I wake up at seven'?",opts:["Me despierto a las siete","Me desperto a las siete","Despierto me a las siete","Me despierta a las siete"],ans:"Me despierto a las siete",hint:"Reflexive pronoun + stem change e to ie."},
        {type:"fb",opts:["Primero","Después","Finalmente","Nunca"],hint:"The sequence word for the first action.",s:"{1} me levanto y luego me ducho.",a:"Primero"},
        {type:"match",pairs:[{trg:"me despierto",src:"I wake up"},{trg:"me ducho",src:"I shower"},{trg:"me visto",src:"I get dressed"},{trg:"desayuno",src:"I have breakfast"},{trg:"me acuesto",src:"I go to bed"}]},
        {type:"mc",q:"Which is correct for 'She always gets up early'?",opts:["Siempre me levanta temprano","Siempre se levanta temprano","Se siempre levanta temprano","Levanta se siempre temprano"],ans:"Siempre se levanta temprano",hint:"___ first, then reflexive pronoun + verb."},
        {type:"fb",opts:["desayunar","desayuno","desayunas","desayuna"],hint:"After + infinitive (base form of the verb).",s:"Después de {1}, voy al trabajo.",a:"desayunar"},
        {type:"drag_fill",hint:"In the morning I study, in the afternoon I work.",s:"Por la mañana {1} español y por la {2} {3} en una oficina.",blanks:{"1":"estudio","2":"tarde","3":"trabajo"},pool:["estudio","tarde","trabajo","estudio","noche","descanso"]},
        {type:"mc",q:"'Me cepillo los dientes' uses 'los' instead of 'mis' because:",opts:["Both forms are equally correct always","Los sounds more natural in this phrase","The reflexive pronoun already shows ownership","Mis is only for clothing items"],ans:"The reflexive pronoun already shows ownership",hint:"The me ___ indicates whose teeth they are."},
        {type:"fb",opts:["juego","jugar","juega","jugamos"],hint:"I play. First person with stem change u to ue.",s:"Los sábados {1} al fútbol con mis amigos.",a:"juego"},
        {type:"mc",q:"Translate: 'I never eat fish.'",opts:["Nunca pescado como","Siempre como pescado","No como nunca pescado","Nunca como pescado"],ans:"Nunca como pescado",hint:"___ goes before the verb."},
        {type:"drag_fill",hint:"After work, I go to the park and then watch TV.",s:"{1} de trabajar, {2} al {3} y luego {4} la tele.",blanks:{"1":"Después","2":"voy","3":"parque","4":"veo"},pool:["Después","voy","parque","veo","Antes","como"]},
        {type:"fb",opts:["veces","siempre","nunca","cada"],hint:"Not always, not never. Occasionally.",s:"A {1} como en un restaurante los viernes.",a:"veces"},
        {type:"mc",q:"Which uses 'a la una' (not 'a las')?",opts:["Como a la una de la tarde","Me levanto a la siete","Me acuesto a la once","Estudio a la tres"],ans:"Como a la una de la tarde",hint:"Only 1:00 uses singular 'a la'. All other hours use 'a las'."},
        {type:"match",pairs:[{trg:"siempre",src:"always"},{trg:"a veces",src:"sometimes"},{trg:"nunca",src:"never"},{trg:"temprano",src:"early"},{trg:"tarde",src:"late"}]},
        {type:"fb",opts:["acuesto","levanto","despierto","ducho"],hint:"The last action of the day is going to bed.",s:"Finalmente me {1} a las once de la noche.",a:"acuesto"},
        {type:"mc",q:"Which pair means 'before' and 'after'?",opts:["primero / luego","antes de / después de","temprano / tarde","siempre / nunca"],ans:"antes de / después de",hint:"These two prepositions are opposites and both use 'de'."},
        {type:"fb",opts:["siempre","nunca","veces","antes"],hint:"She does this every single day without exception.",s:"Ella {1} va al trabajo en autobús.",a:"siempre"},
        {type:"mc",q:"Translate: 'First I shower, then I have breakfast.'",opts:["Finalmente me ducho, luego desayuno","Luego me ducho, primero desayuno","Primero me ducho, luego desayuno","Antes me ducho, después desayuno"],ans:"Primero me ducho, luego desayuno",hint:"First = ___, then = ___."}
  ]},
  {id:"esp5l8b",title:"El Cuerpo",icon:"🧑",xp:18,board:true,steps:[
        {type:"intro",title:"Parts of the Body",desc:"la nariz, el estomago, la rodilla...\n\nBody parts you need for describing pain, visiting the doctor, and daily life.",goals:["Learn 12 body parts in Spanish","Know the gender (el/la) of each","Use body parts with 'me duele' (it hurts me)"]},
        {type:"tip",title:"Doler: It hurts me",deepDive:{
          title:"Doler = Gustar pattern",
          text:"Me duele = it hurts me (one thing)\nMe duelen = they hurt me (multiple)\n\nExactly like gustar:\nMe gusta = I like (one thing)\nMe gustan = I like (plural)"
        },text:"Spanish says 'it hurts TO ME', not 'I hurt':\nMe duele la cabeza. = My head hurts.\nMe duele el estomago. = My stomach hurts.\nMe duelen los pies. = My feet hurt.\n\nSingular: duele. Plural: duelen.\nSame pattern as gustar!"},
        {type:"teach",trg:"la nariz",src:"nose",pos:"noun",gender:"f",phonetic:"la na-REES",note:"La nariz = nose. Feminine.\nResfriado = cold (illness).",example:"A: Me duele la nariz.\nB: Tienes un resfriado.",exampleSrc:"A: My nose hurts.\nB: You have a cold.",funFact:"Irregular plural: 'las narices.' Fun idiom: 'estar hasta las narices' = to be fed up (literally 'to be up to the noses'). One of many body-part expressions Spanish loves."},
        {type:"teach",trg:"el estomago",src:"stomach",pos:"noun",gender:"m",phonetic:"el es-TO-ma-go",note:"El estomago = stomach. Masculine.\nDemasiado = too much.",example:"A: Me duele el estomago.\nB: Comiste demasiado.",exampleSrc:"A: My stomach hurts.\nB: You ate too much.",funFact:"Cognate with English 'stomach'. Spanish and English share many Latin-derived words."},
        {type:"teach",trg:"el cuello",src:"neck",pos:"noun",gender:"m",phonetic:"el KWEH-yo",note:"El cuello = neck. Masculine.",example:"A: Me duele el cuello.\nB: Dormiste mal.",exampleSrc:"A: My neck hurts.\nB: You slept badly.",funFact:"Neck. From Latin 'collum.' Same root as English 'collar' and 'collateral.' 'El cuello' also means a shirt collar; dual meaning through metonymy."},
        {type:"teach",trg:"el hombro",src:"shoulder",pos:"noun",gender:"m",phonetic:"el OM-bro",note:"El hombro = shoulder. Masculine.\nDerecho = right, izquierdo = left.",example:"A: Me duele el hombro derecho.\nB: No lleves la mochila tan pesada.",exampleSrc:"A: My right shoulder hurts.\nB: Don't carry such a heavy backpack.",funFact:"Shoulder. From Latin 'umerus' (shoulder). English 'humerus' (the upper arm bone) shares the root. Spanish dropped the u."},
        {type:"mc",q:"Me duele ___ nariz.",opts:["la","el","los","las"],ans:"la",hint:"La nariz is feminine."},
        {type:"teach",trg:"la rodilla",src:"knee",pos:"noun",gender:"f",phonetic:"la ro-DEE-ya",note:"La rodilla = knee. Feminine.\nCorrer = to run.",example:"A: Me duele la rodilla.\nB: ¿Tu rodilla? ¡Ay! Es muy malo.",exampleSrc:"A: My knee hurts.\nB: Your knee? Oh! That's really bad.",funFact:"Knee. From Latin 'rotella' (little wheel), diminutive of 'rota' (wheel). Knees do rotate. English 'rota' and 'rotary' share this root."},
        {type:"teach",trg:"el pecho",src:"chest",pos:"noun",gender:"m",phonetic:"el PEH-cho",note:"El pecho = chest. Masculine.\nHay que = one must/we need to.",example:"A: Me duele el pecho.\nB: Hay que ir al medico.",exampleSrc:"A: My chest hurts.\nB: We need to go to the doctor.",funFact:"Chest. From Latin 'pectus.' Same root as English 'pectoral.' Also the breast (in compounds: pecho de pollo = chicken breast)."},
        {type:"teach",trg:"la espalda",src:"back",pos:"noun",gender:"f",phonetic:"la es-PAL-da",note:"La espalda = back (of body). Feminine.",example:"A: Me duele la espalda.\nB: Sientate bien.",exampleSrc:"A: My back hurts.\nB: Sit up straight.",funFact:"Back. From Latin 'spatula' (flat blade, shoulder blade). English 'spatula' has the kitchen meaning; Spanish 'espalda' refers to the whole back."},
        {type:"mc",q:"Me duele el estomago means:",opts:["My head hurts","My stomach hurts","I am hungry","I feel sick"],ans:"My stomach hurts",hint:"Estomago is the organ between your chest and waist. Duele follows the gustar pattern."},
        {type:"teach",trg:"el corazon",src:"heart",pos:"noun",gender:"m",phonetic:"el ko-ra-SON",note:"El corazon = heart. Masculine.\nAlso used figuratively: De todo corazon = with all my heart.",example:"A: Me duele el corazon.\nB: ¿Tu corazon? ¡Vamos al medico!",exampleSrc:"A: My heart hurts.\nB: Your heart? Let's go to the doctor!",funFact:"Heart (written 'corazón'). From Latin 'cor' + augmentative -azón. Same Latin root as English 'cordial' and 'cardiac' (via Greek kardia). Spanish favors the augmentative form."},
        {type:"teach",trg:"el codo",src:"elbow",pos:"noun",gender:"m",phonetic:"el KO-do",note:"El codo = elbow. Masculine.",example:"A: Me duele el codo.\nB: Te golpeaste con la mesa?",exampleSrc:"A: My elbow hurts.\nB: Did you hit it on the table?",funFact:"Elbow. From Latin 'cubitus.' Spanish idiom: 'hablar por los codos' (talk through the elbows) = to talk a lot. Creative body-part idioms abound."},
        {type:"teach",trg:"la muneca",src:"wrist",pos:"noun",gender:"f",phonetic:"la mu-NYEH-ka",note:"La muneca = wrist. Also means 'doll'!\nTwo very different meanings, same word.",example:"A: Me duele la muneca.\nB: Escribes mucho en el ordenador.",exampleSrc:"A: My wrist hurts.\nB: You type a lot on the computer.",funFact:"Wrist (also doll). Written 'muñeca' with ñ. The wrist and a doll are etymologically the same word; possibly because early dolls had jointed wrists. Two meanings, one word."},
        {type:"fb",opts:["la","el","los","un"],hint:"La espalda is feminine. Which article?",s:"Me duele {1} espalda.",a:"la"},
        {type:"fb",opts:["duelen","duele","dolor","dolemos"],hint:"Plural body part = plural verb form.",s:"Me {1} los pies.",a:"duelen"},
        {type:"match",pairs:[{trg:"la nariz",src:"nose"},{trg:"el cuello",src:"neck"},{trg:"la rodilla",src:"knee"},{trg:"el hombro",src:"shoulder"}]},
        {type:"match",pairs:[{trg:"el pecho",src:"chest"},{trg:"la espalda",src:"back"},{trg:"el corazon",src:"heart"},{trg:"el estomago",src:"stomach"}]},
        {type:"drag_fill",hint:"My head hurts (singular) and my feet hurt (plural).",s:"Me duele {1} y me duelen {2}.",blanks:{"1":"la cabeza","2":"los pies"},pool:["la cabeza","los pies","el mano","las nariz"]},
        {type:"mc",q:"La muneca means:",opts:["only doll","only wrist","wrist AND doll","ankle"],ans:"wrist AND doll",hint:"Same word, two meanings. Context tells you which."}
  ,{type:"match",pairs:[{trg:"estudiar",src:"to study"},{trg:"el codo",src:"elbow"},{trg:"la muneca",src:"wrist"},{trg:"escuchar",src:"to listen"}]}]},
  {id:"esv2_u5l_essential_a1",title:"Vocabulario Esencial A1: Tiempo y Cortesía",icon:"🗓️",xp:20,board:true,steps:[
    {type:"intro",title:"Vocabulario Esencial A1: Tiempo y Cortesía",desc:"Master 9 high-frequency A1 words: time units (today, hour, week, month, year, day), the word for friend, and two essential politeness expressions.",goals:["Use hoy, el día, la hora, la semana, el mes, el año","Say friend in Spanish (masculine and feminine)","Use de nada and perdón in real conversations"]},
    {type:"teach",trg:"hoy",src:"today",pos:"adv",gender:null,
     phonetic:"oy",
     note:"Hoy = today. Adverb of time.\nUsed constantly in present-tense conversation.\nOpposite: ayer (yesterday) or mañana (tomorrow).",
     example:"A: ¿Qué día es hoy?\nB: Hoy es martes.",
     exampleSrc:"A: What day is today?\nB: Today is Tuesday.",
     funFact:"From Latin hodie (this day). Italian oggi, Portuguese hoje, and French aujourd'hui all share the same root."},
    {type:"teach",trg:"el día",src:"day",pos:"noun",gender:"m",
     phonetic:"el DEE-ah",
     note:"El día = day. Masculine despite ending in -a (an exception).\nBuenos días = good morning (literally 'good days').",
     example:"A: ¿Cuántos días tiene la semana?\nB: La semana tiene siete días.",
     exampleSrc:"A: How many days does the week have?\nB: The week has seven days.",
     funFact:"From Latin dies (day). One of the rare masculine Spanish nouns ending in -a. Día, mapa, and planeta are famous exceptions."},
    {type:"teach",trg:"la hora",src:"hour / the time",pos:"noun",gender:"f",
     phonetic:"la OH-rah",
     note:"La hora = hour or the time of day.\n¿Qué hora es? = What time is it?\nA la una, a las dos... = at one, at two...",
     example:"A: ¿Qué hora es?\nB: Son las tres de la tarde.",
     exampleSrc:"A: What time is it?\nB: It is three in the afternoon.",
     funFact:"From Latin hora. English 'hour' and Spanish hora come from the same root. Ancient Greeks divided the day into 12 equal horas."},
    {type:"teach",trg:"la semana",src:"week",pos:"noun",gender:"f",
     phonetic:"la seh-MAH-nah",
     note:"La semana = week. Feminine.\nEsta semana = this week. La semana que viene = next week.",
     example:"A: ¿Cuántos días hay en la semana?\nB: Hay siete días en la semana.",
     exampleSrc:"A: How many days are in the week?\nB: There are seven days in the week.",
     funFact:"From Latin septimana (group of seven), from septem (seven). The seven-day week spread from Babylon via Greece and Rome to the rest of the world."},
    {type:"teach",trg:"el mes",src:"month",pos:"noun",gender:"m",
     phonetic:"el mes",
     note:"El mes = month. Masculine.\nEste mes = this month. El mes que viene = next month.\nThere are 12 months: enero, febrero... diciembre.",
     example:"A: ¿En qué mes es tu cumpleaños?\nB: Mi cumpleaños es en el mes de marzo.",
     exampleSrc:"A: In which month is your birthday?\nB: My birthday is in the month of March.",
     funFact:"From Latin mensis (month), related to the moon (luna). Ancient calendars tracked months by the lunar cycle, which is about 29.5 days."},
    {type:"teach",trg:"el año",src:"year",pos:"noun",gender:"m",
     phonetic:"el AH-nyoh",
     note:"El año = year. Masculine.\nEste año = this year. El año que viene = next year.\nFeliz Año Nuevo! = Happy New Year!",
     example:"A: ¿Cuántos meses hay en el año?\nB: Hay doce meses en el año.",
     exampleSrc:"A: How many months are in the year?\nB: There are twelve months in the year.",
     funFact:"From Latin annus (year). The tilde on the ñ is key: ano (without tilde) means something very different. Always write año!"},
    {type:"teach",trg:"el amigo / la amiga",src:"friend (m/f)",pos:"noun",gender:"m",
     phonetic:"el ah-MEE-goh / la ah-MEE-gah",
     note:"El amigo = male friend. La amiga = female friend.\nPlural: los amigos (mixed or all-male), las amigas (all-female).",
     example:"A: ¿Tienes un amigo en la clase?\nB: Sí, tengo una amiga. Se llama Lucía.",
     exampleSrc:"A: Do you have a friend in the class?\nB: Yes, I have a friend (female). Her name is Lucía.",
     funFact:"From Latin amicus (friend), related to amare (to love). English 'amicable' comes from the same root."},
    {type:"teach",trg:"de nada",src:"you're welcome",pos:"intj",gender:null,
     phonetic:"deh NAH-dah",
     note:"De nada = you're welcome (literally 'of nothing' / 'it's nothing').\nUsed after someone says gracias.\nAlternative: no hay de qué (more formal).",
     example:"A: Gracias por tu ayuda.\nB: De nada. Es un placer.",
     exampleSrc:"A: Thank you for your help.\nB: You're welcome. It's a pleasure.",
     funFact:"Literally 'of nothing'. Spanish expresses politeness as 'it cost me nothing to help you'. English 'you're welcome' takes the opposite angle."},
    {type:"teach",trg:"perdón",src:"sorry / pardon me",pos:"intj",gender:null,
     phonetic:"per-DON",
     note:"Perdón = sorry or excuse me.\nUsed to apologize or to get someone's attention.\nAccent on the last syllable: per-DON.",
     example:"A: Perdón, ¿hablas español?\nB: Sí, hablo español.",
     exampleSrc:"A: Excuse me, do you speak Spanish?\nB: Yes, I speak Spanish.",
     funFact:"From the verb perdonar (to forgive), from Latin perdonare. English 'pardon' comes from Old French pardonner, which shares the Latin root."},
    {type:"tip",title:"Perdón vs Disculpe",text:"Both mean 'excuse me' or 'sorry', with a small difference in register:\n\nperdón = casual, used with anyone. Works for apologies AND getting attention.\ndisculpe = slightly more formal. Preferred with strangers in formal situations.\n\nFor A1 learners: perdón works in almost every situation.\nWhen in doubt, add a smile.\n\nGracias / de nada is the essential pair: always respond to gracias with de nada.",icon:"💡"},
    {type:"mc",q:"What does 'hoy' mean?",opts:["today","this week","yesterday","tomorrow"],ans:"today",hint:"It describes the current day you are in right now."},
    {type:"fb",opts:["hora","semana","mes","día"],hint:"The unit of time made up of 7 days.",s:"La {1} tiene siete días.",a:"semana"},
    {type:"mc",q:"¿Qué hora es?, when would you say this?",opts:["To ask the day of the week","To ask the current time","To ask the month","To ask the year"],ans:"To ask the current time",hint:"This is a question about what the clock shows right now. Hora = hour."},
    {type:"fb",opts:["año","mes","hora","día"],hint:"This unit of time contains 12 months.",s:"El {1} tiene doce meses.",a:"año"},
    {type:"mc",q:"'El día' is masculine even though it ends in -a. Which other word is the SAME exception?",opts:["el libro","la mesa","el agua","la semana"],ans:"el agua",hint:"A liquid you drink every day, also masculine despite ending in -a. There are only a few such nouns in Spanish."},
    {type:"fb",opts:["De nada","Perdón","Gracias","Hola"],hint:"Someone says 'gracias'. You reply with this expression.",s:"A: Muchas gracias.\nB: {1}, es un placer.",a:"De nada"},
    {type:"match",pairs:[{trg:"hoy",src:"today"},{trg:"el día",src:"day"},{trg:"la semana",src:"week"},{trg:"el mes",src:"month"},{trg:"el año",src:"year"}]},
    {type:"fb",opts:["amiga","amigo","amigos","amigas"],hint:"One female friend. Feminine singular form.",s:"Tengo una {1} en la clase.",a:"amiga"},
    {type:"mc",q:"How do you say 'you're welcome' in Spanish?",opts:["gracias","perdón","hola","de nada"],ans:"de nada",hint:"Literally means 'of nothing'. Said after someone thanks you."},
    {type:"fb",opts:["Perdón","Gracias","De nada","Hola"],hint:"You bumped into someone by accident. What do you say first?",s:"{1}, no es mi intención.",a:"Perdón"},
    {type:"mc",q:"Complete: 'Este ___ tengo un examen.' (this month)",opts:["mes","semana","hora","año"],ans:"mes",hint:"The time unit smaller than a year but larger than a week."},
    {type:"fb",opts:["semana","mes","año","día"],hint:"There are 7 of these in a week.",s:"La semana tiene siete {1}s.",a:"día"},
    {type:"mc",q:"A friend helps you carry a bag and says 'gracias'. You respond:",opts:["Gracias","De nada","Hoy","Perdón"],ans:"De nada",hint:"This expression responds to gracias. It means the help was no trouble at all."},
    {type:"match",pairs:[{trg:"el amigo / la amiga",src:"friend (m/f)"},{trg:"de nada",src:"you're welcome"},{trg:"perdón",src:"sorry / pardon me"},{trg:"la hora",src:"hour / the time"}]}
  ]}
]};
